import React, { useState, useEffect, Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { 
  OrbitControls, 
  useGLTF, 
  Environment, 
  Stage,
  ContactShadows,
  Sparkles,
  Html
} from "@react-three/drei";
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function Model({ modelPath }) {
  const { scene } = useGLTF(modelPath);
  return <primitive object={scene} />;
}

// Preload the model
useGLTF.preload("http://localhost:3000/public/uploads/3dmodels/ferrari_f8_tributo.glb");

const GameView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [autoRotate, setAutoRotate] = useState(true);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/api/v1/products/${id}`);
        setProduct(response.data);
        setLoading(false);
      } catch (err) {
        console.error('Error loading product:', err);
        navigate('/');
      }
    };
    fetchProduct();
  }, [id, navigate]);

  if (loading) {
    return (
      <div className="fixed top-0 left-0 w-full h-full bg-black flex items-center justify-center text-white">
        Loading 3D viewer...
      </div>
    );
  }

  if (!product?.model3D) {
    return (
      <div className="fixed top-0 left-0 w-full h-full bg-black flex items-center justify-center text-white">
        3D model not available for this product
      </div>
    );
  }

  return (
    <div className="fixed top-0 left-0 w-full h-full bg-zinc-900 flex">
      {/* 3D Viewer Section */}
      <div className="w-1/2 h-full relative border-r-2 border-zinc-800">
        <Canvas camera={{ position: [0, 2, 5], fov: 50, near: 0.1, far: 1000 }}>
          <Suspense fallback={
            <Html center>
              <div className="text-white text-2xl">Loading masterpiece...</div>
            </Html>
          }>
            {/* Scene Lighting */}
            <ambientLight intensity={0.5} />
            <directionalLight
              position={[5, 5, 5]}
              intensity={1.5}
              castShadow
              shadow-mapSize-width={2048}
              shadow-mapSize-height={2048}
            />

            {/* Floating Particles */}
            <Sparkles
              count={150}
              size={4}
              speed={0.4}
              opacity={0.8}
              color="#ef4444"
              scale={20}
              noise={0.8}
              position={[0, 0, 0]}
              depth={10}
              fade={false}
              spawnRate={0.5}
            />

            {/* Main Model Display */}
            <Stage environment="dawn" intensity={0.5} adjustCamera={false}>
              {product?.model3D && (
                <>
                  <Model 
                    modelPath={`http://localhost:3000/public/uploads/3dmodels/${product.model3D}`}
                    scale={0.8}
                    position={[0, -12, 222]}
                  />
                  <ContactShadows
                    frames={0}
                    position={[0, 0, 0]}
                    opacity={0.4}
                    scale={10}
                    blur={2.5}
                    far={1}
                  />
                </>
              )}
            </Stage>

            {/* Floor Reflection
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]}>
              <circleGeometry args={[5, 64]} />
              <meshStandardMaterial
                color="#1a1a1a"
                metalness={0.5}
                roughness={0.3}
                transparent
                opacity={0.5}
              />
            </mesh> */}

            {/* Camera Controls */}
            <OrbitControls 
              enablePan={true}
              enableZoom={true}
              enableRotate={true}
              autoRotate={autoRotate}
              autoRotateSpeed={2}
              maxDistance={10}
              minDistance={4}
              minPolarAngle={Math.PI/6}
              maxPolarAngle={Math.PI/2}
              target={[0, 0.5, 0]}
              dampingFactor={0.1}
              onChange={() => setAutoRotate(false)}
            />

            {/* Environment Effects */}
            <Environment preset="sunset" background blur={0.5} />
          </Suspense>
        </Canvas>
      </div>

      {/* Product Details Section */}
      <div className="w-1/2 h-full overflow-y-auto bg-gradient-to-br from-zinc-900 to-zinc-950 p-8">
        {product && (
          <div className="space-y-8">
            {/* Header */}
            <div className="border-b border-zinc-800 pb-8">
              <button
                onClick={() => navigate(-1)}
                className="mb-6 text-zinc-400 hover:text-white transition-colors"
              >
                <i className="fas fa-arrow-left mr-2"></i>Back to Product
              </button>
              <h1 className="text-4xl font-bold mb-4">{product.name}</h1>
              <p className="text-xl text-zinc-400">{product.shortDescription}</p>
            </div>

            {/* Pricing Section */}
            <div className="bg-zinc-800/50 p-6 rounded-2xl">
              <div className="flex items-baseline gap-4 mb-4">
                <span className="text-3xl font-bold">${product.price}</span>
                {product.oldPrice && (
                  <span className="text-zinc-400 line-through">${product.oldPrice}</span>
                )}
              </div>
              <button className="w-full py-4 bg-red-500 hover:bg-red-600 rounded-xl transition-all">
                Add to Cart
              </button>
            </div>

            {/* Specifications */}
            <div className="grid grid-cols-2 gap-6">
              <div className="col-span-2">
                <h2 className="text-2xl font-bold mb-4">Specifications</h2>
              </div>
              <div className="space-y-2">
                <span className="text-zinc-400">Collection</span>
                <p className="font-medium">{product.collection?.name}</p>
              </div>
              <div className="space-y-2">
                <span className="text-zinc-400">Scale</span>
                <p className="font-medium">{product.scale}</p>
              </div>
              <div className="space-y-2">
                <span className="text-zinc-400">Material</span>
                <p className="font-medium">{product.material}</p>
              </div>
              <div className="space-y-2">
                <span className="text-zinc-400">Dimensions</span>
                <p className="font-medium">{product.dimensions}</p>
              </div>
            </div>

            {/* Features */}
            <div className="space-y-4">
              <h2 className="text-2xl font-bold">Features</h2>
              <ul className="grid grid-cols-2 gap-4">
                {product.features?.map((feature, index) => (
                  <li key={index} className="flex items-center gap-3 p-4 bg-zinc-800/50 rounded-xl">
                    <i className="fas fa-check text-red-500"></i>
                    {feature}
                  </li>
                ))}
              </ul>
            </div>

            {/* Full Description */}
            <div className="space-y-4">
              <h2 className="text-2xl font-bold">Detailed Description</h2>
              <p className="text-zinc-400 leading-relaxed">{product.description}</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default GameView;
